SELECT [RigaFatturaPerresi-step0].[Sell-to Customer No_], [RigaFatturaPerresi-step0].[Sell-to Customer Name], [RigaFatturaPerresi-step0].CCR, [RigaFatturaPerresi-step0].MARCHIO, [RigaFatturaPerresi-step0].STAGIONE, [RigaFatturaPerresi-step0].LINEA, [RigaFatturaPerresi-step0].[Sales Invoice Header].No_, [RigaFatturaPerresi-step0].[posting date], [RigaFatturaPerresi-step0].[Salesperson Code], [RigaFatturaPerresi-step0].[Area Manager Code], [RigaFatturaPerresi-step0].[Subject 1], [RigaFatturaPerresi-step0].[Subject 2], [RigaFatturaPerresi-step0].SalespersonCommission, [RigaFatturaPerresi-step0].AreaManagerCommission, [RigaFatturaPerresi-step0].Subject1Commission, [RigaFatturaPerresi-step0].Subject2Commission, [RigaFatturaPerresi-step0].[Sales Invoice Line].No_, [RigaFatturaPerresi-step0].[Description 2], [RigaFatturaPerresi-step0].Color, [RigaFatturaPerresi-step0].PrezzoUnitario, [RigaFatturaPerresi-step0].importoLordoRIga, [RigaFatturaPerresi-step0].importoNettoRIga, [RigaFatturaPerresi-step0].ImportoScontoFattura, [RigaFatturaPerresi-step0].ImportoScontoRIga, [RigaFatturaPerresi-step0].[VAT Identifier], [RigaFatturaPerresi-step1].ScontoRIgaTot, [RigaFatturaPerresi-step1].ScontoRiga, [RigaFatturaPerresi-step1].ScontoRiga1, [RigaFatturaPerresi-step1].ScontoRiga2, [RigaFatturaPerresi-step1].ScontoRiga3, [RigaFatturaPerresi-step1].ScontoFattura, [RigaFatturaPerresi-step0].[Tariff No_], [RigaFatturaPerresi-step0].[Country_Region of Origin Code]
FROM [RigaFatturaPerresi-step0] INNER JOIN [RigaFatturaPerresi-step1] ON ([RigaFatturaPerresi-step0].[Shipment Line No_] = [RigaFatturaPerresi-step1].[Line No_]) AND ([RigaFatturaPerresi-step0].[Shipment No_] = [RigaFatturaPerresi-step1].[Document No_]);

